1	type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	type QuoteStep = { op: "quote"; items: Item[] };
9	
10	type Damage = { itemType: string; amount: number };
11	type Incident = { cause: string; damages: Damage[] };
12	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
13	
14	type Policy = {
15	  items: Item[];
16	  insuranceSum: number;
17	  remainingCap: number;
18	};
19	
20	type Step = QuoteStep | ClaimStep;
21	
22	export type Scenario = {
23	  customer: { yearsWithMHPCO: number };
24	  steps: Step[];
25	};
26	
27	export type ScenarioResult = {
28	  results: Array<Record<string, unknown>>;
29	};
30	
31	const PROCESSING_FEE = 5;
32	
33	const BASE_PREMIUMS: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	  rune: 25,
39	  moonstone: 25,
40	};
41	
42	const INSURANCE_VALUE_MULTIPLIER = 10;
43	
44	const DEDUCTIBLE = 100;
45	const CAP_MULTIPLIER = 2;
46	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
47	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
48	
49	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
50	
51	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
52	
53	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
54	const BLOCK_SIZE = 3;
55	const BLOCK_PREMIUM = 60;
56	
57	const groupByType = (items: Item[]): Map<string, Item[]> => {
58	  const groups = new Map<string, Item[]>();
59	  for (const item of items) {
60	    const group = groups.get(item.type) ?? [];
61	    group.push(item);
62	    groups.set(item.type, group);
63	  }
64	  return groups;
65	};
66	
67	const baseTotalForGroup = (group: Item[]): number => {
68	  const type = group[0].type;
69	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
70	    return BLOCK_PREMIUM;
71	  }
72	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
73	};
74	
75	const baseTotalFor = (items: Item[]): number => {
76	  let total = 0;
77	  for (const group of groupByType(items).values()) {
78	    total += baseTotalForGroup(group);
79	  }
80	  return total;
81	};
82	
83	const CURSED_SURCHARGE_RATE = 0.5;
84	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
85	const HIGH_ENCHANTMENT_THRESHOLD = 5;
86	const LOYALTY_DISCOUNT_RATE = -0.2;
87	const LOYALTY_YEARS_THRESHOLD = 2;
88	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = -0.15;
89	
90	type Customer = { yearsWithMHPCO: number };
91	
92	type QuoteContext = {
93	  items: Item[];
94	  customer: Customer;
95	  isFollowUpContract: boolean;
96	};
97	
98	type PolicyModifier = {
99	  applies: (ctx: QuoteContext) => boolean;
100	  rate: number;
101	};
102	
103	const POLICY_MODIFIERS: PolicyModifier[] = [
104	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE_RATE },
105	  {
106	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
107	    rate: LOYALTY_DISCOUNT_RATE,
108	  },
109	  { applies: (ctx) => ctx.isFollowUpContract, rate: FOLLOWUP_CONTRACT_DISCOUNT_RATE },
110	];
111	
112	const itemSurchargeRateFor = (item: Item): number => {
113	  let rate = 0;
114	  if (item.cursed) rate += CURSED_SURCHARGE_RATE;
115	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
116	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
117	  }
118	  return rate;
119	};
120	
121	const itemSurchargesFor = (items: Item[]): number =>
122	  items.reduce((sum, item) => sum + basePremiumFor(item) * itemSurchargeRateFor(item), 0);
123	
124	const policyModifiersTotal = (baseTotal: number, ctx: QuoteContext): number =>
125	  POLICY_MODIFIERS.reduce(
126	    (sum, mod) => (mod.applies(ctx) ? sum + baseTotal * mod.rate : sum),
127	    0,
128	  );
129	
130	const quotePremium = (
131	  items: Item[],
132	  customer: Customer,
133	  isFollowUpContract: boolean,
134	): number => {
135	  const ctx: QuoteContext = { items, customer, isFollowUpContract };
136	  const baseTotal = baseTotalFor(items);
137	  return Math.ceil(
138	    baseTotal +
139	      itemSurchargesFor(items) +
140	      policyModifiersTotal(baseTotal, ctx) +
141	      PROCESSING_FEE,
142	  );
143	};
144	
145	const insuranceValueFor = (item: Item): number =>
146	  basePremiumFor(item) * INSURANCE_VALUE_MULTIPLIER;
147	
148	const insuranceSumFor = (items: Item[]): number =>
149	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
150	
151	const reimbursementFor = (item: Item, damageAmount: number): number => {
152	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD) {
153	    return damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
154	  }
155	  return damageAmount;
156	};
157	
158	const payoutForDamage = (item: Item, damage: Damage): number => {
159	  return Math.max(0, reimbursementFor(item, damage.amount) - DEDUCTIBLE);
160	};
161	
162	const findItemOfType = (policy: Policy, itemType: string): Item | undefined =>
163	  policy.items.find((item) => item.type === itemType);
164	
165	const assertDamageAmountNonNegative = (damage: Damage): void => {
166	  if (damage.amount < 0) {
167	    throw new Error(`Damage amount must not be negative: ${damage.amount}`);
168	  }
169	};
170	
171	const assertDamageItemInPolicy = (policy: Policy, damage: Damage): void => {
172	  if (!findItemOfType(policy, damage.itemType)) {
173	    throw new Error(`Damage references item not in policy: ${damage.itemType}`);
174	  }
175	};
176	
177	const countByType = <T extends { type?: string; itemType?: string }>(
178	  entries: T[],
179	  keyOf: (entry: T) => string,
180	): Map<string, number> => {
181	  const counts = new Map<string, number>();
182	  for (const entry of entries) {
183	    const key = keyOf(entry);
184	    counts.set(key, (counts.get(key) ?? 0) + 1);
185	  }
186	  return counts;
187	};
188	
189	const assertDamageCountsWithinPolicy = (policy: Policy, incident: Incident): void => {
190	  const insuredCounts = countByType(policy.items, (item) => item.type);
191	  const damageCounts = countByType(incident.damages, (damage) => damage.itemType);
192	  for (const [itemType, count] of damageCounts) {
193	    if (count > (insuredCounts.get(itemType) ?? 0)) {
194	      throw new Error(
195	        `Claim has more damages of type ${itemType} than policy covers`,
196	      );
197	    }
198	  }
199	};
200	
201	const validateClaimDamages = (policy: Policy, incident: Incident): void => {
202	  for (const damage of incident.damages) {
203	    assertDamageAmountNonNegative(damage);
204	    assertDamageItemInPolicy(policy, damage);
205	  }
206	  assertDamageCountsWithinPolicy(policy, incident);
207	};
208	
209	const grossPayoutFor = (policy: Policy, incident: Incident): number =>
210	  incident.damages.reduce(
211	    (sum, damage) => sum + payoutForDamage(findItemOfType(policy, damage.itemType)!, damage),
212	    0,
213	  );
214	
215	const processClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
216	  validateClaimDamages(policy, incident);
217	  const payout = Math.floor(Math.min(grossPayoutFor(policy, incident), policy.remainingCap));
218	  policy.remainingCap -= payout;
219	  return { payout, remainingCap: policy.remainingCap };
220	};
221	
222	const newPolicy = (items: Item[]): Policy => {
223	  const insuranceSum = insuranceSumFor(items);
224	  return { items, insuranceSum, remainingCap: insuranceSum * CAP_MULTIPLIER };
225	};
226	
227	const KNOWN_ITEM_TYPES = new Set(Object.keys(BASE_PREMIUMS));
228	
229	const validateQuoteItems = (items: Item[]): void => {
230	  for (const item of items) {
231	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
232	      throw new Error(`Unknown item type: ${item.type}`);
233	    }
234	  }
235	};
236	
237	export const runScenario = (scenario: Scenario): ScenarioResult => {
238	  let quoteCount = 0;
239	  const policies: Record<number, Policy> = {};
240	
241	  const handleQuote = (quote: QuoteStep, index: number) => {
242	    validateQuoteItems(quote.items);
243	    const isFollowUp = quoteCount > 0;
244	    quoteCount += 1;
245	    policies[index] = newPolicy(quote.items);
246	    return { premium: quotePremium(quote.items, scenario.customer, isFollowUp) };
247	  };
248	
249	  const handleClaim = (claim: ClaimStep) =>
250	    processClaim(policies[claim.policy], claim.incident);
251	
252	  const results = scenario.steps.map((step, index) =>
253	    step.op === "quote" ? handleQuote(step, index) : handleClaim(step),
254	  );
255	  return { results };
256	};
